parameters.jsCode:
// 1. Obtenemos todos los datos que llegan del nodo anterior (la IA)
const items = $input.all();

// 2. Procesamos cada item para convertir el texto en JSON real
const transformedItems = items.map((item) => {
  // Limpiamos los posibles bloques de código (```json ... ```) 
  // que la IA suele agregar por defecto
  const outputString = item.json.output.replace(/```json|```/g, '').trim();

  // Convertimos el string de texto limpio en un objeto JSON real
  const output = JSON.parse(outputString);

  // Devolvemos el objeto procesado
  return {
    json: output
  };
});

// 3. Enviamos los datos listos al siguiente nodo
return transformedItems;

